def parse_python_calls(text: str) -> dict[str, Any]:
    """Parse one or more Python-style function call expressions into the `ToolCalls` dict format.

    This accepts only a minimal, safe subset of Python: top-level call expressions (e.g. `search(q="nlp")`),
    one per line or separated by `;`, with keyword-only arguments whose values are literals (strings, numbers,
    booleans, `None`, and dicts/lists/tuples thereof). Nothing is evaluated; the source is only parsed to an AST
    and walked.

    Args:
        text: The source text containing one or more Python-style call expressions.

    Returns:
        A dict of the form `{"tool_calls": [{"name": ..., "args": {...}}, ...]}`, in source order.
    """
    try:
        tree = ast.parse(text, mode="exec")
    except SyntaxError as e:
        raise ValueError(f"Could not parse tool call(s): invalid Python syntax ({e.msg}).")

    if not tree.body:
        raise ValueError("No tool call found in the input.")

    tool_calls = []
    for node in tree.body:
        if not isinstance(node, ast.Expr) or not isinstance(node.value, ast.Call):
            raise ValueError("Only function call expressions are supported, e.g. `search(query=\"hello\")`.")
        tool_calls.append(_convert_call_node(node.value))

    return {"tool_calls": tool_calls}


def _convert_call_node(call: ast.Call) -> dict[str, Any]:
    name = _extract_call_name(call.func)

    if call.args:
        raise ValueError(
            f"Only keyword arguments supported when calling `{name}`; found positional argument(s). "
            'Please use keyword arguments instead, e.g. `foo(a=1, b="x")`.'
        )

    args = {}
    for kw in call.keywords:
        if kw.arg is None:
            raise ValueError(f"Only keyword arguments supported when calling `{name}`; found `**kwargs` expansion.")
        args[kw.arg] = _convert_literal(kw.value, name)

    return {"name": name, "args": args}


def _extract_call_name(func_node: ast.AST) -> str:
    if isinstance(func_node, ast.Name):
        return func_node.id
    if isinstance(func_node, ast.Attribute):
        _validate_attribute_chain(func_node.value)
        return func_node.attr
    raise ValueError("Only simple function names are supported, e.g. `foo(...)` or `pkg.foo(...)`.")


def _validate_attribute_chain(node: ast.AST) -> None:
    if isinstance(node, ast.Name):
        return
    if isinstance(node, ast.Attribute):
        _validate_attribute_chain(node.value)
        return
    raise ValueError("Only simple function names are supported, e.g. `foo(...)` or `pkg.foo(...)`.")


def _convert_literal(node: ast.AST, call_name: str) -> Any:
    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.UnaryOp) and isinstance(node.op, (ast.USub, ast.UAdd)):
        if isinstance(node.operand, ast.Constant) and isinstance(node.operand.value, (int, float)):
            value = node.operand.value
            return -value if isinstance(node.op, ast.USub) else value
        raise ValueError(f"Only literal values are allowed in call to `{call_name}`.")

    if isinstance(node, ast.Dict):
        if any(k is None for k in node.keys):
            raise ValueError(
                f"Only literal values are allowed in call to `{call_name}`; dict expansion (`**`) is not supported."
            )
        return {_convert_literal(k, call_name): _convert_literal(v, call_name) for k, v in zip(node.keys, node.values)}

    if isinstance(node, ast.List):
        return [_convert_literal(elt, call_name) for elt in node.elts]

    if isinstance(node, ast.Tuple):
        # Convert tuples to lists for JSON compatibility.
        return [_convert_literal(elt, call_name) for elt in node.elts]

    raise ValueError(f"Only literal values are allowed in call to `{call_name}`; found `{type(node).__name__}`.")


def _split_inline_comment(line: str) -> tuple[str, str | None]:
    """Split a line into (code, comment) around the first unquoted `#`."""
    in_string = False
    quote_char = ""
    for i, ch in enumerate(line):
        if in_string:
            if ch == quote_char and line[i - 1] != "\\":
                in_string = False
        elif ch in ("'", '"'):
            in_string = True
            quote_char = ch
        elif ch == "#":
            return line[:i], line[i + 1 :]
    return line, None


def _extract_json_objects(text: str) -> list[str]:
    """Extract all top-level, balanced `{...}` blocks from `text`, ignoring braces inside string literals."""
    objects = []
    depth = 0
    start = None
    in_string = False
    quote_char = ""
    for i, ch in enumerate(text):
        if in_string:
            if ch == quote_char and text[i - 1] != "\\":
                in_string = False
            continue
        if ch in ("'", '"'):
            in_string = True
            quote_char = ch
            continue
        if ch == "{":
            if depth == 0:
                start = i
            depth += 1
        elif ch == "}":
            depth -= 1
            if depth == 0 and start is not None:
                objects.append(text[start : i + 1])
                start = None
    return objects


